+  const canvasRef = useRef<HTMLCanvasElement>(null);
+  const [agents, setAgents] = useState<AgentInfo[]>(DEFAULT_AGENTS);
+
+  // Poll agents every 5 seconds
+  useEffect(() => {
+    let active = true;
+    const poll = () => {
+      fetch('/api/agents')
+        .then((r) => r.ok ? r.json() : [])
+        .then((data: AgentInfo[]) => {
+          if (active && Array.isArray(data) && data.length > 0) setAgents(data);
+        })
+        .catch(() => {});
+    };
+    poll();
+    const iv = setInterval(poll, 5000);
+    return () => { active = false; clearInterval(iv); };
+  }, []);
+
+  // Define minimap room colors
+  const MINIMAP_ROOM_COLORS: Record<string, string> = {
+    king: '#FFD700',       // gold (Throne)
+    squire: '#FFA500',     // orange (Workshop)
+    scribe: '#0000FF',     // blue (Library)
+    knight: '#FF0000',     // red (War Room)
+    healer: '#008000',     // green (Healing)
+    sentinel: '#808080',   // gray (Watchtower)
+    judge: '#A52A2A',      // brown (Scribe)
+    blacksmith: '#2F4F4F', // dark gray (Dungeon)
+    nobility: '#800080',   // purple (Great Hall)
+  };
+
+  // Map the ROOM_GRID labels to requested room names/colors:
+  // Throne(gold) = king
+  // Workshop(orange) = squire
+  // Library(blue) = scribe
+  // War Room(red) = knight
+  // Healing(green) = healer
+  // Watchtower(gray) = sentinel
+  // Scribe(brown) = judge
+  // Dungeon(dark gray) = blacksmith
+  // Great Hall(purple) = nobility
+
+  // Map tier to minimap room name for legend (not used here but for clarity)
+  // We will draw simplified rectangles for rooms with colored dots for agents inside.
+
+  useEffect(() => {
+    if (!canvasRef.current) return;
+
+    const cancel = startGameLoop((_dt, frameCount) => {
+      const rc = syncCanvasSize(canvasRef.current!);
+      clearCanvas(rc);
+
+      // Draw main scene as before
+      const cols = 3;
+      const padding = 10;
+      const labelH = 24;
+      const roomW = Math.floor((rc.width - padding * (cols + 1)) / cols);
+      const roomH = Math.min(Math.floor(roomW * 0.7), 180);
+
+      // Group agents by tier
+      const agentsByTier = new Map<string, AgentInfo[]>();
+      for (const a of agents) {
+        const list = agentsByTier.get(a.tier) ?? [];
+        list.push(a);
+        agentsByTier.set(a.tier, list);
+      }
+
+      for (const slot of ROOM_GRID) {
+        const rx = padding + slot.col * (roomW + padding);
+        const ry = padding + slot.row * (roomH + labelH + padding + 6);
+
+        // Room label with shadow
+        drawText(rc, slot.label.toUpperCase(), rx + 5, ry + 15, 11, '#000000');
+        drawText(rc, slot.label.toUpperCase(), rx + 4, ry + 14, 11, COLORS.gold);
+
+        // Room background
+        drawRoom(rc.ctx, slot.tier, rx, ry + labelH, roomW, roomH, frameCount);
+
+        // Room border (double line for depth)
+        rc.ctx.strokeStyle = '#2a2030';
+        rc.ctx.lineWidth = 2;
+        rc.ctx.strokeRect(rx, ry + labelH, roomW, roomH);
+        rc.ctx.strokeStyle = '#5a5a6a';
+        rc.ctx.lineWidth = 1;
+        rc.ctx.strokeRect(rx + 1, ry + labelH + 1, roomW - 2, roomH - 2);
+
+        // Draw agents in this room (cap visible at 4, show overflow badge)
+        const tierAgents = agentsByTier.get(slot.tier) ?? [];
+        const maxVisible = 4;
+        const visible = tierAgents.slice(0, maxVisible);
+        const overflow = tierAgents.length - visible.length;
+        const charScale = Math.min(2.5, roomW / 90);
+        visible.forEach((agent, i) => {
+          // Spread characters within the room's walkable area
+          const startX = rx + roomW * 0.15 + i * Math.min(55, (roomW * 0.7) / Math.max(1, visible.length));
+          const startY = ry + labelH + roomH * 0.45;
+
+          // Update character movement
+          const cs = getCS(agent.id, startX, startY);
+          const walkBounds = {
+            x: rx + roomW * 0.08,
+            y: ry + labelH + roomH * 0.38,
+            w: roomW * 0.84,
+            h: roomH * 0.45,
+          };
+          updateMovement(cs, walkBounds);
+
+          const animState = agent.state as AnimState;
+          drawCharacter(rc.ctx, slot.tier as CharacterType, animState, cs.x, cs.y, charScale, frameCount, agent.id, agent.currentJob);
+
+          // Name plate (below character)
+          const nameY = cs.y + 24 * charScale;
+          drawText(rc, agent.name, cs.x - 4, nameY, 9, COLORS.text);
+          // State badge
+          const stateColor = getStateColor(agent.state);
+          drawText(rc, agent.state, cs.x - 4, nameY + 12, 8, stateColor);
+        });
+
+        // Overflow badge
+        if (overflow > 0) {
+          const badgeX = rx + roomW - 30;
+          const badgeY = ry + labelH + 8;
+          rc.ctx.fillStyle = '#4a2060';
+          rc.ctx.fillRect(badgeX, badgeY, 24, 14);
+          rc.ctx.strokeStyle = COLORS.gold;
+          rc.ctx.lineWidth = 1;
+          rc.ctx.strokeRect(badgeX, badgeY, 24, 14);
+          drawText(rc, `+${overflow}`, badgeX + 3, badgeY + 11, 9, COLORS.gold);
+        }
+
+        if (tierAgents.length === 0) {
+          drawText(rc, '— vacant —', rx + roomW * 0.3, ry + labelH + roomH * 0.55, 10, '#555');
+        }
+      }
+
+      // --- Draw minimap overlay ---
+      // Minimap size and position
+      const minimapWidth = 160;
+      const minimapHeight = 120;
+      const margin = 12;
+      const mmX = rc.width - minimapWidth - margin;
+      const mmY = margin;
+
+      // Draw dark semi-transparent background
+      rc.ctx.save();
+      rc.ctx.fillStyle = 'rgba(20, 20, 20, 0.8)';
+      rc.ctx.fillRect(mmX, mmY, minimapWidth, minimapHeight);
+
+      // Define minimap grid: 3 cols x 4 rows (to fit 9 rooms)
+      const mmCols = 3;
+      const mmRows = 4;
+      const mmPadding = 6;
+      const mmRoomW = (minimapWidth - mmPadding * (mmCols + 1)) / mmCols;
+      const mmRoomH = (minimapHeight - mmPadding * (mmRows + 1)) / mmRows;
+
+      // Map tiers to minimap grid positions (col, row)
+      // Use ROOM_GRID positions for consistency
+      // Rooms: Throne(gold) = king, Workshop(orange) = squire, Library(blue) = scribe,
+      // War Room(red) = knight, Healing(green) = healer, Watchtower(gray) = sentinel,
+      // Scribe(brown) = judge, Dungeon(dark gray) = blacksmith, Great Hall(purple) = nobility
+
+      // Draw rooms as rectangles with their color
+      for (const slot of ROOM_GRID) {
+        const col = slot.col;
+        const row = slot.row;
+        const rx = mmX + mmPadding + col * (mmRoomW + mmPadding);
+        const ry = mmY + mmPadding + row * (mmRoomH + mmPadding);
+
+        // Room color from mapping or fallback gray
+        const roomColor = MINIMAP_ROOM_COLORS[slot.tier] ?? '#444444';
+
+        // Draw room rectangle
+        rc.ctx.fillStyle = roomColor;
+        rc.ctx.globalAlpha = 0.6;
+        rc.ctx.fillRect(rx, ry, mmRoomW, mmRoomH);
+        rc.ctx.globalAlpha = 1.0;
+
+        // Draw room border
+        rc.ctx.strokeStyle = '#222222';
+        rc.ctx.lineWidth = 1;
+        rc.ctx.strokeRect(rx, ry, mmRoomW, mmRoomH);
+
+        // Draw agent dots inside room
+        const agentsInRoom = agentsByTier.get(slot.tier) ?? [];
+        const dotRadius = 4;
+        const maxDotsPerRow = Math.floor((mmRoomW - 4) / (dotRadius * 2 + 2));
+        const maxDots = maxDotsPerRow * 2; // two rows max
+        const count = Math.min(agentsInRoom.length, maxDots);
+
+        for (let i = 0; i < count; i++) {
+          const dotX = rx + 4 + (i % maxDotsPerRow) * (dotRadius * 2 + 2) + dotRadius;
+          const dotY = ry + 4 + Math.floor(i / maxDotsPerRow) * (dotRadius * 2 + 2) + dotRadius;
+
+          // Dot color: use tier color but brighter for visibility
+          rc.ctx.fillStyle = roomColor;
+          rc.ctx.beginPath();
+          rc.ctx.shadowColor = '#000000';
+          rc.ctx.shadowBlur = 2;
+          rc.ctx.shadowOffsetX = 0;
+          rc.ctx.shadowOffsetY = 0;
+          rc.ctx.arc(dotX, dotY, dotRadius, 0, 2 * Math.PI);
+          rc.ctx.fill();
+          rc.ctx.shadowBlur = 0;
+        }
+      }
+
+      rc.ctx.restore();
+    });
+
+    return cancel;
+  }, [agents]);
+
+  return (
+    <canvas
+      ref={canvasRef}
+      style={{ display: 'block', width: '100%', height: 'calc(100vh - 40px)' }}
+    />
+  );
+}
